import { tags } from 'decantr/tags';
import { list } from 'decantr/core';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Avatar, Badge, Button } from 'decantr/components';

code.example:
function ActivityFeed({ search: extSearch } = {}) {
  const { div, span, h3 } = tags;
  const [visibleCount, setVisibleCount] = createSignal(4);
  const items = [
    { avatar: '', user: 'Alice Chen', action: 'deployed v2.4.1 to production', time: '2 min ago', type: 'success' },
    { avatar: '', user: 'Bob Patel', action: 'opened pull request #142', time: '15 min ago', type: 'default' },
    { avatar: '', user: 'Carol Liu', action: 'commented on issue #89', time: '1 hour ago', type: 'default' },
    { avatar: '', user: 'Dan Kim', action: 'merged branch feature/auth', time: '3 hours ago', type: 'success' },
    { avatar: '', user: 'Eve Zhao', action: 'updated project settings', time: '5 hours ago', type: 'default' },
    { avatar: '', user: 'Frank Wu', action: 'closed issue #85', time: '1 day ago', type: 'success' }
  ];
  const visibleItems = () => {
    let filtered = items;
    if (extSearch) {
      const s = extSearch().toLowerCase();
      if (s) filtered = filtered.filter(i => i.user.toLowerCase().includes(s) || i.action.toLowerCase().includes(s));
    }
    return filtered.slice(0, visibleCount());
  };

  return div({ class: css('_flex _col _gap2 _p4') },
    h3({ class: css('_heading5') }, 'Recent Activity'),
    list(visibleItems, (item) => item.user, item =>
      div({ class: css('_flex _gap3 _aic _py2 _borderB') },
        Avatar({ src: item.avatar, name: item.user, size: 'sm' }),
        div({ class: css('_flex _col _flex1') },
          span({ class: css('_textsm') }, span({ class: css('_bold') }, item.user), ` ${item.action}`),
          span({ class: css('_textxs _fgmuted') }, item.time)
        ),
        Badge({ variant: item.type === 'success' ? 'success' : 'default' }, item.type)
      )
    ),
    () => visibleCount() < items.length ? Button({ variant: 'ghost', class: css('_wfull _mt2'), onclick: () => setVisibleCount(visibleCount() + 4) }, 'Load More') : null
  );
}

