function NotificationCenter({ notifications }) {
  const { div, span, h4 } = tags;
  const grouped = {};
  notifications.forEach(n => { (grouped[n.date] = grouped[n.date] || []).push(n); });

  return div({ class: css('_flex _col _gap0') },
    ...Object.entries(grouped).flatMap(([date, items]) => [
      div({ class: css('_px4 _py2 _bgmuted/10') },
        span({ class: css('_textxs _bold _fgmuted') }, date)
      ),
      ...items.map(item =>
        div({ class: css(`_flex _gap3 _aic _px4 _py3 _borderB ${item.unread ? '_bgprimary/5' : ''}`) },
          div({ class: css('_flex _center _w8 _h8 _r2 _bgprimary/10') },
            icon(item.icon, { size: '1em', class: css('_fgprimary') })
          ),
          div({ class: css('_flex _col _flex1') },
            span({ class: css(`_textsm ${item.unread ? '_bold' : ''}`) }, item.message),
            span({ class: css('_textxs _fgmuted') }, item.time)
          ),
          Button({ variant: 'ghost', size: 'sm' }, icon('x', { size: '1em' }))
        )
      )
    ])
  );
}

