function ActivityFeedGrouped({ search: extSearch, view: extView } = {}) {
  const { div, span, h3, time } = tags;
  const groups = [
    { name: 'decantr/core', items: [
      { user: 'Alice', action: 'pushed 3 commits', time: '10 min ago', status: 'active' },
      { user: 'Bob', action: 'opened PR #42', time: '1 hour ago', status: 'active' }
    ]},
    { name: 'decantr/docs', items: [
      { user: 'Carol', action: 'updated tutorial page', time: '2 hours ago', status: 'active' },
      { user: 'Dan', action: 'fixed typo in API docs', time: '3 hours ago', status: 'archived' },
      { user: 'Eve', action: 'added SSR guide', time: '5 hours ago', status: 'draft' }
    ]},
    { name: 'decantr/cli', items: [
      { user: 'Frank', action: 'released v1.2.0', time: '1 day ago', status: 'active' }
    ]}
  ];
  function getFiltered() {
    const v = extView ? extView() : 'all';
    const s = extSearch ? extSearch().toLowerCase() : '';
    return groups.map(group => {
      let items = group.items;
      if (v && v !== 'all') items = items.filter(i => i.status === v);
      if (s) items = items.filter(i => i.user.toLowerCase().includes(s) || i.action.toLowerCase().includes(s));
      return { ...group, items };
    }).filter(g => g.items.length > 0);
  }
  function renderGroup(group) {
    const [open, setOpen] = createSignal(true);
    return div({ class: css('_flex _col _gap0 _borderB _pb2') },
      Button({ variant: 'ghost', class: css('_flex _aic _jcsb _wfull _py2'), onclick: () => setOpen(!open()) },
        div({ class: css('_flex _aic _gap2') },
          icon('folder', { size: '1em' }),
          span({ class: css('_textsm _bold') }, group.name),
          Badge({ size: 'sm' }, `${group.items.length}`)
        ),
        cond(() => open(), () => icon('chevron-up', { size: '1em' }), () => icon('chevron-down', { size: '1em' }))
      ),
      cond(() => open(), () => div({ class: css('_flex _col _gap1 _pl6') },
        ...group.items.map(item =>
          div({ class: css('_flex _aic _gap2 _py1') },
            Avatar({ name: item.user, size: 'xs' }),
            span({ class: css('_textsm') }, span({ class: css('_bold') }, item.user), ` ${item.action}`),
            time({ class: css('_textxs _fgmuted _mlis[auto] _shrink0') }, item.time)
          )
        )
      ))
    );
  }

  return div({ class: css('_flex _col _gap2') },
    h3({ class: css('_heading5') }, 'Activity'),
    () => {
      const filtered = getFiltered();
      if (!filtered.length) return span({ class: css('_fgmuted _textsm _p4') }, 'No matching activity');
      const wrap = div({ class: css('_flex _col _gap0') });
      filtered.forEach(g => wrap.appendChild(renderGroup(g)));
      return wrap;
    }
  );
}

